'use strict';

const { DynamoDBClient } = require('@aws-sdk/client-dynamodb');
const { DynamoDBDocumentClient } = require('@aws-sdk/lib-dynamodb');

const ddbClient = new DynamoDBClient({});
const ddb = DynamoDBDocumentClient.from(ddbClient, {
  marshallOptions: { removeUndefinedValues: true },
});

const TableNames = {
  USERS: process.env.USERS_TABLE,
  CATEGORY_STATS: process.env.CATEGORY_STATS_TABLE,
  DAILY_LOGS: process.env.DAILY_LOGS_TABLE,
  XP_EVENTS: process.env.XP_EVENTS_TABLE,
  FRIEND_REQUESTS: process.env.FRIEND_REQUESTS_TABLE,
  FRIENDSHIPS: process.env.FRIENDSHIPS_TABLE,
  COMMUNITIES: process.env.COMMUNITIES_TABLE,
};

module.exports = { ddb, TableNames };
